#include <vector>
#include <algorithm>
#include <string>

using namespace std;

string solve(string s, long long k) {
    vector<char> result;
    for (char c : s) {
        if (islower(c)) {
            result.push_back(c);
        } else if (c == '*' && !result.empty()) {
            result.pop_back();
        } else if (c == '#') {
            vector<char> copy = result;
            result.insert(result.end(), copy.begin(), copy.end());
        } else if (c == '%') {
            reverse(result.begin(), result.end());
        }
    }
    if (k >= 0 && k < static_cast<long long>(result.size())) {
        return string(1, result[k]);
    } else {
        return ".";
    }
}
